#include<bits/stdc++.h>
#define rep(a,b,c) for(int c=(a);c<=(b);++c)
#define drep(a,b,c) for(int c=(a);c>=(b);--c)
#define grep(a,b,c) for(int c=a.head[(b)];c;c=a.nxt[c])
using namespace std;
inline int read()
{
	int res=0;char ch=getchar();bool flag=0;
	while(ch<'0'||ch>'9')flag^=(ch=='-'),ch=getchar();
	while(ch<='9'&&ch>='0')res=res*10+(ch^48),ch=getchar();
	return flag ? -res : res ;
}
multiset<int> s1,s2;multiset<int> :: iterator it;
const int N=2e5+10;int n,ans=0x3f3f3f3f,siz[N];
struct Graph
{
	int head[N],des[N<<1],nxt[N<<1],cnt;
	inline void ins(int x,int y){nxt[++cnt]=head[x];des[head[x]=cnt]=y;}
}a;
inline void chk(int x,int y){int z=n-x-y;ans=min(ans,max(max(x,y),z)-min(min(x,y),z));}
inline void dfs1(int u,int fa){siz[u]=1;grep(a,u,i){int v=a.des[i];if(v^fa)dfs1(v,u),siz[u]+=siz[v];}}
inline void dfs2(int u,int fa)
{
	if(!s1.empty())
	{
		it=s1.lower_bound(((n-siz[u])>>1)+siz[u]);
		if(it!=s1.end())chk(siz[u],*it-siz[u]);
		if(it!=s1.begin())--it,chk(siz[u],*it-siz[u]);
	}
	if(!s2.empty())
	{
		it=s2.lower_bound((n-siz[u])>>1);
		if(it!=s2.end())chk(siz[u],*it);
		if(it!=s2.begin())--it,chk(siz[u],*it);
	}
	if(u^1)s1.insert(siz[u]);
	grep(a,u,i){int v=a.des[i];if(v==fa)continue;dfs2(v,u);}
	if(u^1)s1.erase(s1.find(siz[u])),s2.insert(siz[u]);
}
int main()
{
	n=read();rep(2,n,i){int x=read(),y=read();a.ins(x,y);a.ins(y,x);}
	dfs1(1,0);dfs2(1,0);printf("%d\n",ans);return 0;
}
